-- =============================================================================
-- EXCHANGE RATES MODULE — SQLC QUERIES
-- File: db/queries/fxrates.sql
--
-- Type-safe Go for the exchange_rates table (defined in db/schema/fxrates_schema.sql).
-- Generated by a DEDICATED sqlc block (see sqlc.yaml) into package `fxrates` at
-- db/exchange_rates.
--
-- Global reference data: no organisation_id, no soft-delete. WRITTEN by the
-- background refresh (UpsertRate), READ by the invoices auto-fill and the FX
-- revaluation job (GetRateOnOrBefore / GetRate / ListRatesOnDate).
-- =============================================================================


-- -----------------------------------------------------------------------------
-- UpsertRate — store (or overwrite) one currency's rate for one date.
-- The refresh calls this once per currency per run; ON CONFLICT makes re-running a
-- day's fetch idempotent (last-write-wins on the natural key).
-- -----------------------------------------------------------------------------
-- name: UpsertRate :exec
INSERT INTO exchange_rates (currency, rate_date, rate, source)
VALUES (sqlc.arg(currency), sqlc.arg(rate_date), sqlc.arg(rate), sqlc.arg(source))
ON CONFLICT (currency, rate_date)
DO UPDATE SET rate = EXCLUDED.rate, source = EXCLUDED.source, created_at = now();


-- -----------------------------------------------------------------------------
-- GetRateOnOrBefore — the latest rate for a currency at or before a date.
-- This is THE lookup used everywhere: it falls back to the most recent prior
-- trading day when the exact date has no published rate (weekend/holiday), and the
-- rate > 0 filter is belt-and-braces with the column CHECK. Returns no rows when we
-- have never stored a rate for the currency — callers treat that as "no rate".
-- -----------------------------------------------------------------------------
-- name: GetRateOnOrBefore :one
SELECT currency, rate_date, rate, source
FROM exchange_rates
WHERE currency = sqlc.arg(currency) AND rate_date <= sqlc.arg(rate_date) AND rate > 0
ORDER BY rate_date DESC
LIMIT 1;


-- -----------------------------------------------------------------------------
-- GetRate — the exact rate for a currency on a specific date (no fallback).
-- Used where an exact-date hit is required (e.g. asserting a refresh wrote a row).
-- -----------------------------------------------------------------------------
-- name: GetRate :one
SELECT currency, rate_date, rate, source
FROM exchange_rates
WHERE currency = sqlc.arg(currency) AND rate_date = sqlc.arg(rate_date);


-- -----------------------------------------------------------------------------
-- ListRatesOnDate — every currency's rate at or before a date (one row per
-- currency, its most recent rate). Backs the GET /api/v1/exchange-rates list so the
-- SPA can show a full table for a chosen date. DISTINCT ON keeps the newest per
-- currency given the DESC ordering.
-- -----------------------------------------------------------------------------
-- name: ListRatesOnDate :many
SELECT DISTINCT ON (currency) currency, rate_date, rate, source
FROM exchange_rates
WHERE rate_date <= $1 AND rate > 0
ORDER BY currency, rate_date DESC;
